module shift_register (
	input clk,
	input reset,
	input shift,
	input load,
	input [3:0] parallel_in,
	output [3:0] q
);reg [3:0] r_reg;

always @(posedge clk or posedge reset) begin
	if (reset)
		r_reg <= 4'b0000;
	else if (load)
		r_reg <= parallel_in;
	else if (shift)
		r_reg <= {r_reg[2:0], 1'b0};
end

assign q = r_reg;

endmodule
